class Solution:
    def minPatches(self, nums, n):
        patches = 0
        reach = 0
        queue = list(nums)
        pos = 0
        while reach < n:
            nxt = reach + 1
            if pos < len(queue) and queue[pos] <= nxt:
                reach += queue[pos]
                pos += 1
            else:
                reach += nxt
                patches += 1
        return patches

