var minPatches = function(nums, n) {
    let patches = 0;
    let miss = 1;
    let i = 0;
    const length = nums.length;
    while (miss <= n) {
        if (i < length && nums[i] <= miss) {
            miss += nums[i];
            i += 1;
        } else {
            miss += miss;
            patches += 1;
        }
    }
    return patches;
};
